/**
 * Theme definition types and built-in themes for T3 Code.
 *
 * This module is intentionally dependency-free so it can be consumed by both
 * the server and the web app without pulling in browser or React APIs.
 */

export interface ThemeColors {
  /** Main application background */
  background: string;
  /** Primary text color */
  foreground: string;
  /** Accent / interactive highlight color (buttons, links, focus rings) */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Editor pane background */
  editor: string;
  /** Integrated terminal background */
  terminal: string;
  /** Status bar / bottom bar background */
  statusBar: string;
}

export interface Theme {
  /** Unique identifier, e.g. "t3-dark" */
  id: string;
  /** Human-readable display name */
  name: string;
  /** Color palette for this theme */
  colors: ThemeColors;
  /** CSS font-family stack applied to the UI */
  fontFamily: string;
  /** Base font size in pixels */
  fontSize: number;
  /** Whether this is a dark or light color scheme */
  colorScheme: "dark" | "light";
}

const SANS_SERIF_STACK =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    fontFamily: SANS_SERIF_STACK,
    fontSize: 14,
    colors: {
      background: "oklch(0.124 0 0)",
      foreground: "oklch(0.95 0 0)",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.105 0 0)",
      editor: "oklch(0.135 0 0)",
      terminal: "oklch(0.09 0 0)",
      statusBar: "oklch(0.08 0 0)",
    },
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colorScheme: "light",
    fontFamily: SANS_SERIF_STACK,
    fontSize: 14,
    colors: {
      background: "oklch(1 0 0)",
      foreground: "oklch(0.269 0 0)",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.97 0 0)",
      editor: "oklch(1 0 0)",
      terminal: "oklch(0.95 0 0)",
      statusBar: "oklch(0.93 0 0)",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colorScheme: "dark",
    fontFamily: SANS_SERIF_STACK,
    fontSize: 14,
    colors: {
      background: "oklch(0.11 0.02 264)",
      foreground: "oklch(0.92 0.015 264)",
      accent: "oklch(0.62 0.22 264)",
      sidebar: "oklch(0.09 0.024 264)",
      editor: "oklch(0.12 0.016 264)",
      terminal: "oklch(0.085 0.018 264)",
      statusBar: "oklch(0.075 0.022 264)",
    },
  },
] as const;

/**
 * Returns all available built-in themes. The first entry is the default.
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Returns the theme with the given id.
 * Falls back to the default theme ("t3-dark") if the id is not found.
 */
export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? (BUILT_IN_THEMES[0] as Theme);
}

