  createContext,
  createElement,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useSyncExternalStore,
} from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

// ─── Module-level store ───────────────────────────────────────────────────────
//
// Keeping state at module scope (rather than only inside the React tree) lets
// us apply the correct theme before the first React render, preventing flash
// of unstyled content (FOUC).

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

let listeners: Array<() => void> = [];
let cachedSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw && listThemes().some((t) => t.id === raw)) return raw;
  } catch {
    // localStorage unavailable (test env, SSR, etc.)
  }
  return DEFAULT_THEME_ID;
}

function applyThemeToDom(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle the `.dark` class used by Tailwind's dark variant
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");

  // Write theme color tokens as CSS custom properties on :root
  const root = document.documentElement;
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  root.style.setProperty("--sidebar-background", theme.colors.sidebar);
  root.style.setProperty("--editor-background", theme.colors.editor);
  root.style.setProperty("--terminal-background", theme.colors.terminal);
  root.style.setProperty("--status-bar-background", theme.colors.statusBar);

  // Apply font preferences via the body element
  if (document.body) {
    document.body.style.fontFamily = theme.fontFamily;
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of unstyled content
applyThemeToDom(getTheme(getStoredId()));

function getSnapshot(): Theme {
  const theme = getTheme(getStoredId());
  if (cachedSnapshot?.id === theme.id) return cachedSnapshot;
  cachedSnapshot = theme;
  return cachedSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme changes that originate from other browser tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      cachedSnapshot = null;
      applyThemeToDom(getTheme(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─── React context ────────────────────────────────────────────────────────────

export interface ThemeContextValue {
  /** The active Theme object */
  theme: Theme;
  /** Switch to a different theme by id */
  setTheme: (id: string) => void;
  /** All available built-in themes */
  availableThemes: readonly Theme[];
  /**
   * Resolved color scheme — always "light" or "dark".
   * Kept for backward compatibility with diff/syntax-highlight components.
   */
  resolvedTheme: "light" | "dark";
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides theme state to the React tree.
 * Wire this into the router's `Wrap` so every route has access.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // ignore write failures
    }
    cachedSnapshot = null;
    applyThemeToDom(getTheme(id), true);
    emitChange();
  }, []);

  // Keep DOM in sync when the snapshot changes (e.g. cross-tab storage events)
  useEffect(() => {
    applyThemeToDom(theme);
  }, [theme]);

  const availableThemes = useMemo(() => listThemes(), []);
  const resolvedTheme = theme.colorScheme;

  const value = useMemo<ThemeContextValue>(
    () => ({ theme, setTheme, availableThemes, resolvedTheme }),
    [theme, setTheme, availableThemes, resolvedTheme],
  );

  return createElement(ThemeContext.Provider, { value }, children);
}

/**
 * Access the current theme and theme controls.
 * Must be called inside a component rendered within `<ThemeProvider>`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used inside <ThemeProvider>");
  }
  return ctx;
}

