import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

interface SwatchProps {
  color: string;
  label: string;
}

function Swatch({ color, label }: SwatchProps) {
  return (
    <span
      className="inline-block h-3.5 w-3.5 rounded-full border border-black/10"
      style={{ backgroundColor: color }}
      title={label}
      aria-hidden="true"
    />
  );
}

interface ThemeCardProps {
  theme: Theme;
  selected: boolean;
  onSelect: () => void;
}

function ThemeCard({ theme, selected, onSelect }: ThemeCardProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent hover:text-foreground"
      }`}
      onClick={onSelect}
    >
      <span className="flex flex-col gap-2">
        <span className="text-sm font-medium leading-none">{theme.name}</span>

        {/* Color preview swatches */}
        <span className="flex items-center gap-1.5" aria-label="Theme color preview">
          <Swatch color={theme.colors.background} label="Background" />
          <Swatch color={theme.colors.foreground} label="Foreground" />
          <Swatch color={theme.colors.accent} label="Accent" />
          <Swatch color={theme.colors.sidebar} label="Sidebar" />
          <Swatch color={theme.colors.editor} label="Editor" />
          <Swatch color={theme.colors.terminal} label="Terminal" />
          <Swatch color={theme.colors.statusBar} label="Status bar" />
        </span>
      </span>

      {selected ? (
        <span className="ml-3 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

/**
 * Displays all available themes as selectable cards with color-swatch previews.
 * Drop this into any settings surface that needs theme selection.
 */
export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((theme) => (
        <ThemeCard
          key={theme.id}
          theme={theme}
          selected={currentTheme.id === theme.id}
          onSelect={() => setTheme(theme.id)}
        />
      ))}
    </div>
  );
}

